import { Request, Response } from "express";
import { prisma } from "../config/database";

class AgendamentosController {
  async listar(req: Request, res: Response) {
    try {
      const userId = (req as any).user?.id;
      // se não autenticado, retorna lista pública simulada
      if (!userId) {
        const simulated = [
          { id: '1', medico: 'Dr. Lucas Ribeiro', especialidade: 'Cardiologia', data: new Date().toISOString(), status: 'confirmado' }
        ];
        return res.json(simulated);
      }

      const agendamentos = await prisma.agendamento.findMany({
        where: { usuarioId: userId },
        include: { profissional: { include: { usuario: true } } },
        orderBy: { dataHora: 'desc' },
      });

      // Log detalhado para diagnóstico
      console.log('Agendamentos encontrados:', JSON.stringify(agendamentos, null, 2));

      const mapped = agendamentos.map(a => ({
        id: a.id,
        medico: a.profissional?.usuario?.nome || null,
        especialidade: a.profissional?.especialidade || null,
        data: a.dataHora,
        status: a.status,
      }));

      console.log('Agendamentos mapeados:', JSON.stringify(mapped, null, 2));

      return res.json(mapped);
    } catch (err) {
      console.error('Erro ao listar agendamentos', err);
      return res.status(500).json({ 
        error: 'Erro ao listar agendamentos', 
        details: err instanceof Error ? err.message : err,
        stack: err instanceof Error && err.stack ? err.stack : undefined
      });
    }
  }

  async sugerirHorarios(req: Request, res: Response) {
    try {
      const { medicoId } = req.query;
      if (!medicoId) return res.status(400).json({ error: 'medicoId é obrigatório' });

      // Horários sugeridos: próximos 7 dias, 8h-17h, 30min cada, sem conflito
      const horarios: string[] = [];
      const now = new Date();
      for (let dia = 0; dia < 7; dia++) {
        const data = new Date(now);
        data.setDate(now.getDate() + dia);
        for (let hora = 8; hora < 17; hora++) {
          for (let min = 0; min < 60; min += 30) {
            const slot = new Date(data);
            slot.setHours(hora, min, 0, 0);
            // Verifica conflito
            const conflito = await prisma.agendamento.findFirst({
              where: {
                profissionalId: String(medicoId),
                dataHora: slot,
                status: { in: ['agendado', 'confirmado'] },
              },
            });
            if (!conflito && slot > now) {
              horarios.push(slot.toISOString());
            }
            if (horarios.length >= 10) break;
          }
          if (horarios.length >= 10) break;
        }
        if (horarios.length >= 10) break;
      }
      return res.json(horarios);
    } catch (err) {
      console.error('Erro ao sugerir horários', err);
      return res.status(500).json({ error: 'Erro ao sugerir horários' });
    }
  }
}

export default AgendamentosController;

import { Request, Response } from "express";
import { prisma } from "../config/database";
import logger from "../utils/logger";

class AgendamentosController {
  async listar(req: Request, res: Response) {
    try {
      const userId = (req as any).user?.id;
      if (!userId) {
        return res.status(401).json({ error: "Usuário não autenticado" });
      }

      const agendamentos = await prisma.agendamento.findMany({
        where: { usuarioId: userId },
        include: { profissional: { include: { usuario: true } } },
        orderBy: { dataHora: 'desc' },
      });

      const mapped = agendamentos.map(a => ({
        id: a.id,
        medico: a.profissional?.usuario?.nome || null,
        especialidade: a.profissional?.especialidade || null,
        data: a.dataHora,
        status: a.status,
      }));

      return res.json(mapped);
    } catch (err) {
      logger.error('Erro ao listar agendamentos', err);
      return res.status(500).json({ error: 'Erro ao listar agendamentos' });
    }
  }

  async sugerirHorarios(req: Request, res: Response) {
    try {
      const { medicoId } = req.query;
      if (!medicoId) return res.status(400).json({ error: 'medicoId é obrigatório' });

      const horarios: string[] = [];
      const now = new Date();
      for (let dia = 0; dia < 7; dia++) {
        const data = new Date(now);
        data.setDate(now.getDate() + dia);
        for (let hora = 8; hora < 17; hora++) {
          for (let min = 0; min < 60; min += 30) {
            const slot = new Date(data);
            slot.setHours(hora, min, 0, 0);
            const conflito = await prisma.agendamento.findFirst({
              where: {
                profissionalId: String(medicoId),
                dataHora: slot,
                status: { in: ['agendado', 'confirmado'] },
              },
            });
            if (!conflito && slot > now) {
              horarios.push(slot.toISOString());
            }
            if (horarios.length >= 10) break;
          }
          if (horarios.length >= 10) break;
        }
        if (horarios.length >= 10) break;
      }
      return res.json(horarios);
    } catch (err) {
      logger.error('Erro ao sugerir horários', err);
      return res.status(500).json({ error: 'Erro ao sugerir horários' });
    }
  }
}

export default AgendamentosController;

import { Request, Response } from "express";
import { prisma } from "../config/database";
import logger from "../utils/logger";

class ContatosController {
  async criar(req: Request, res: Response) {
    try {
      const { profissionalId, assunto, mensagem } = req.body;
      const usuarioId = (req as any).user?.id;
      if (!usuarioId) return res.status(401).json({ error: "Usuário não autenticado" });
      if (!profissionalId || !assunto || !mensagem) return res.status(400).json({ error: "Preencha todos os campos" });

      const contato = await prisma.contato.create({ data: { usuarioId, profissionalId, assunto, mensagem } });
      logger.success(`Contato criado: ${contato.id}`);
      return res.status(201).json(contato);
    } catch (err) {
      logger.error("Erro ao criar contato", err);
      return res.status(500).json({ error: "Erro ao criar contato" });
    }
  }

  async listar(req: Request, res: Response) {
    try {
      const usuarioId = (req as any).user?.id;
      if (!usuarioId) return res.status(401).json({ error: "Usuário não autenticado" });

      const contatos = await prisma.contato.findMany({ where: { OR: [{ usuarioId }, { profissionalId: usuarioId }] }, orderBy: { criado_em: "desc" } });
      return res.json(contatos);
    } catch (err) {
      logger.error("Erro ao listar contatos", err);
      return res.status(500).json({ error: "Erro ao listar contatos" });
    }
  }
}

export default new ContatosController();

import { Request, Response } from "express";
import { prisma } from "../config/database";
import logger from "../utils/logger";

class ContatosController {
  async criar(req: Request, res: Response) {
    try {
      const { profissionalId, assunto, mensagem } = req.body;
      const usuarioId = (req as any).user?.id;
      if (!usuarioId) return res.status(401).json({ error: "Usuário não autenticado" });
      if (!profissionalId || !assunto || !mensagem) return res.status(400).json({ error: "Preencha todos os campos" });

      const contato = await prisma.contato.create({ data: { usuarioId, profissionalId, assunto, mensagem } });
      logger.success(`Contato criado: ${contato.id}`);
      return res.status(201).json(contato);
    } catch (err) {
      logger.error("Erro ao criar contato", err);
      return res.status(500).json({ error: "Erro ao criar contato" });
    }
  }

  async listar(req: Request, res: Response) {
    try {
      const usuarioId = (req as any).user?.id;
      if (!usuarioId) return res.status(401).json({ error: "Usuário não autenticado" });

      // Busca o profissional vinculado ao usuário (caso seja médico)
      const profissional = await prisma.profissional.findUnique({ where: { usuarioId } });

      const contatos = await prisma.contato.findMany({
        where: {
          OR: [
            { usuarioId },
            // Se o usuário é um profissional, mostra também os contatos recebidos
            ...(profissional ? [{ profissionalId: profissional.id }] : []),
          ],
        },
        orderBy: { criado_em: "desc" },
      });
      return res.json(contatos);
    } catch (err) {
      logger.error("Erro ao listar contatos", err);
      return res.status(500).json({ error: "Erro ao listar contatos" });
    }
  }
}

export default new ContatosController();

import { Request, Response } from "express";
import { prisma } from "../config/database";

class MedicosController {
    async recomendados(req: Request, res: Response) {
      try {
        // Profissionais com mais agendamentos (top 10)
        const profs = await prisma.profissional.findMany({
          include: {
            usuario: true,
            _count: { select: { agendamentos: true } },
          },
        });

        const top = profs
          .map(p => ({
            id: p.id,
            nome: p.usuario?.nome || null,
            especialidade: p.especialidade,
            cidade: p.cidade,
            estado: p.estado,
            avatar: p.usuario?.avatar || null,
            totalAgendamentos: p._count?.agendamentos ?? 0,
          }))
          .sort((a, b) => b.totalAgendamentos - a.totalAgendamentos)
          .slice(0, 10);

        return res.json(top);
      } catch (err) {
        console.error('Erro ao recomendar profissionais', err);
        return res.status(500).json({ error: 'Erro ao recomendar profissionais' });
      }
    }
  async listar(req: Request, res: Response) {
    try {
      const { query, especialidade } = req.query as any;
      const where: any = {};
      if (especialidade) where.especialidade = { contains: especialidade, mode: 'insensitive' };

      // Busca profissionais com dados do usuário associado
      const profs = await prisma.profissional.findMany({
        where,
        include: { usuario: true },
        take: 50,
      });

      const mapped = profs.map(p => ({
        id: p.id,
        nome: p.usuario?.nome || null,
        especialidade: p.especialidade,
        cidade: p.cidade,
        estado: p.estado,
        avatar: p.usuario?.avatar || null,
      }));

      return res.json(mapped);
    } catch (err) {
      console.error('Erro ao listar profissionais', err);
      return res.status(500).json({ error: 'Erro ao listar profissionais' });
    }
  }
}

export default new MedicosController();

import { Request, Response } from "express";
import { prisma } from "../config/database";
import logger from "../utils/logger";

class MedicosController {
  async recomendados(req: Request, res: Response) {
    try {
      const profs = await prisma.profissional.findMany({
        include: {
          usuario: true,
          _count: { select: { agendamentos: true } },
        },
      });

      const top = profs
        .map(p => ({
          id: p.id,
          nome: p.usuario?.nome || null,
          especialidade: p.especialidade,
          cidade: p.cidade,
          estado: p.estado,
          avatar: p.usuario?.avatar || null,
          totalAgendamentos: p._count?.agendamentos ?? 0,
        }))
        .sort((a, b) => b.totalAgendamentos - a.totalAgendamentos)
        .slice(0, 10);

      return res.json(top);
    } catch (err) {
      logger.error('Erro ao recomendar profissionais', err);
      return res.status(500).json({ error: 'Erro ao recomendar profissionais' });
    }
  }

  async listar(req: Request, res: Response) {
    try {
      const { query, especialidade } = req.query as { query?: string; especialidade?: string };
      const where: any = {};

      if (especialidade) {
        where.especialidade = { contains: especialidade, mode: 'insensitive' };
      }

      // Filtra pelo nome do usuário se ?query= for fornecido
      if (query) {
        where.usuario = { nome: { contains: query, mode: 'insensitive' } };
      }

      const profs = await prisma.profissional.findMany({
        where,
        include: { usuario: true },
        take: 50,
      });

      const mapped = profs.map(p => ({
        id: p.id,
        nome: p.usuario?.nome || null,
        especialidade: p.especialidade,
        cidade: p.cidade,
        estado: p.estado,
        avatar: p.usuario?.avatar || null,
      }));

      return res.json(mapped);
    } catch (err) {
      logger.error('Erro ao listar profissionais', err);
      return res.status(500).json({ error: 'Erro ao listar profissionais' });
    }
  }
}

export default new MedicosController();

import { Request, Response } from "express";
import { prisma } from "../config/database";

class ProfessionalController {
  async meSummary(req: Request, res: Response) {
    try {
      const userId = (req as any).user?.id;
      if (!userId) return res.status(401).json({ error: 'Usuário não autenticado' });

      const profissional = await prisma.profissional.findUnique({ where: { usuarioId: userId } });
      if (!profissional) return res.status(404).json({ error: 'Profissional não encontrado' });

      // Agendamentos de hoje
      const start = new Date();
      start.setHours(0, 0, 0, 0);
      const end = new Date(start);
      end.setDate(end.getDate() + 1);

      const totalToday = await prisma.agendamento.count({ where: { profissionalId: profissional.id, dataHora: { gte: start, lt: end } } });

      // Próximos agendamentos (limit 10)
      const nextAppointments = await prisma.agendamento.findMany({
        where: { profissionalId: profissional.id, dataHora: { gte: new Date() } },
        include: { usuario: { select: { id: true, nome: true, telefone: true } } },
        orderBy: { dataHora: 'asc' },
        take: 10,
      });

      // Média de avaliação
      const ratingAgg = await prisma.avaliacao.aggregate({ where: { profissionalId: profissional.id }, _avg: { nota: true } });
      const ratingAvg = ratingAgg._avg.nota ?? null;

      // Receita do mês atual (somente pagamentos ligados a agendamentos do profissional)
      const now = new Date();
      const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
      const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 1);

      const revenueAgg = await prisma.pagamento.aggregate({
        where: { agendamento: { profissionalId: profissional.id, dataHora: { gte: monthStart, lt: monthEnd } } },
        _sum: { valorFinal: true },
      });
      const revenueThisMonth = revenueAgg._sum.valorFinal ?? 0;

      // Pendências: contatos não lidos
      const pendingContacts = await prisma.contato.count({ where: { profissionalId: profissional.id, status: 'nao_lido' } });

      return res.json({
        profissional: { id: profissional.id, especialidade: profissional.especialidade },
        totalToday,
        nextAppointments,
        ratingAvg,
        revenueThisMonth,
        pendingContacts,
      });
    } catch (err) {
      console.error('Professional summary error', err);
      return res.status(500).json({ error: 'Erro ao gerar resumo do profissional' });
    }
  }
}

