    prisma.contato.create({ data: { usuarioId: fernanda.id, profissionalId: pJuliana.id, assunto: "Resultado de exame",        mensagem: "Recebi os resultados dos exames solicitados. Posso enviar para análise?",             status: "lido"    } }),
